/* в”Җв”Җ Do Export в”Җв”Җ */
function ieDoExport(table, label){
  var sb = getSB();
  if(!sb){ toast('Database tidak terhubung','err'); return; }
  toast('Mengambil data '+label+'вҖҰ','info');
  if(window.ProgUI) ProgUI.open({title:'Export '+label, step:'Memuat data referensi (Area/OLT/ODC/ODP/Material)вҖҰ'});

  /* Header ramah untuk kolom FK */
  var _fkHeader = {
    area_id:'Area', area_coverage_id:'Coverage Area',
    olt_id:'OLT', odc_id:'ODC', odp_id:'ODP',
    ont_item_id:'ONT', kabel_item_id:'Kabel', material_item_id:'Material',
    kecamatan_id:'Kecamatan', kelurahan_id:'Kelurahan'
  };

  /* Fetch semua tabel referensi sekaligus (paralel), lalu buat lookup idвҶ’label */
  Promise.all([
    sb.from('areas').select('id,nama').then(function(r){ return r.data||[]; }).catch(function(){ return []; }),
    sb.from('olts').select('id,kode').then(function(r){ return r.data||[]; }).catch(function(){ return []; }),
    sb.from('odcs').select('id,kode').then(function(r){ return r.data||[]; }).catch(function(){ return []; }),
    sb.from('odps').select('id,kode,nama').then(function(r){ return r.data||[]; }).catch(function(){ return []; }),
    sb.from('material_items').select('id,nama').then(function(r){ return r.data||[]; }).catch(function(){ return []; }),
    sb.from('wilayah').select('id,kecamatan,kelurahan').then(function(r){ return r.data||[]; }).catch(function(){ return []; })
  ]).then(function(results){
    /* Bangun lookup: { uuid: 'nama yang mudah dibaca' } per kolom FK */
    var _lookup = {};
    function _addLookup(list, field){
      (list||[]).forEach(function(x){ if(x.id) _lookup[x.id] = x[field]||x.nama||x.kode||'вҖ”'; }); /* tidak pakai UUID sebagai label */
    }
    _addLookup(results[0], 'nama');   /* areas */
    _addLookup(results[1], 'kode');   /* olts */
    _addLookup(results[2], 'kode');   /* odcs */
    /* odps: pakai kode, fallback nama */
    (results[3]||[]).forEach(function(x){ if(x.id) _lookup[x.id] = x.kode||x.nama||'вҖ”'; }); /* tidak pakai UUID sebagai label */
    _addLookup(results[4], 'nama');   /* material_items */
    /* wilayah: kecamatan_id вҶ’ kecamatan, kelurahan_id вҶ’ kelurahan */
    (results[5]||[]).forEach(function(x){
      if(x.id) _lookup[x.id+'__kecamatan'] = x.kecamatan||x.id;
      if(x.id) _lookup[x.id+'__kelurahan'] = x.kelurahan||x.id;
    });

    function _resolve(col, uuid){
      if(!uuid) return '';
      if(col==='kecamatan_id') return _lookup[uuid+'__kecamatan']||uuid;
      if(col==='kelurahan_id') return _lookup[uuid+'__kelurahan']||uuid;
      return _lookup[uuid]||uuid;
    }

    function _isUUID(v){
      return typeof v==='string' && /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(v);
    }

    /* Fetch data utama */
    if(window.ProgUI) ProgUI.step('Mengambil data '+label+' dari databaseвҖҰ', 45);

    if(table === 'maintenance'){
      var mntJenisExp=['ont_replace','kabel_replace','odp_maintenance','odc_maintenance','signal_check','maintenance_ont','maintenance_kabel','odp_port_move'];
      var matById = {}; (results[4]||[]).forEach(function(m){ matById[m.id]=m.nama; });
      sb.from('material_mutasi').select('*').in('jenis', mntJenisExp).order('tgl',{ascending:false})
        .then(function(rm){
          if(rm.error){ toast('Gagal export: '+(rm.error.message||'coba lagi'),'err'); if(window.ProgUI)ProgUI.error('Gagal export: '+(rm.error.message||'coba lagi')); return; }
          var mdata = rm.data||[];
          if(!mdata.length){ toast('Tidak ada data untuk diekspor','err'); if(window.ProgUI)ProgUI.error('Tidak ada data untuk diekspor'); return; }
          if(window.ProgUI) ProgUI.step('Menyusun '+mdata.length+' baris menjadi CSVвҖҰ', 75);
          var jLblExp={maintenance_ont:'Ganti ONT',ont_replace:'Ganti ONT',maintenance_kabel:'Ganti Kabel',kabel_replace:'Ganti Kabel',odp_maintenance:'Maint. ODP',odc_maintenance:'Maint. ODC',odp_port_move:'Pindah Port',signal_check:'Cek Sinyal'};
          var mntCols=['tgl','jenis','item','jumlah','pel_cid','teknisi','sn_ont','keterangan'];
          var headerRow = ['"No"'].concat(mntCols.map(function(c){ return '"'+c+'"'; })).join(',');
          var csv = headerRow + '\n';
          mdata.forEach(function(row, idx){
            var vals = {
              tgl: row.tgl||'', jenis: jLblExp[row.jenis]||row.jenis||'',
              item: matById[row.item_id]||'', jumlah: row.jumlah||'',
              pel_cid: row.pel_cid||'', teknisi: row.teknisi||'',
              sn_ont: row.sn_ont||'', keterangan: row.keterangan||''
            };
            var line = ['"'+(idx+1)+'"'].concat(mntCols.map(function(c){
              return '"'+String(vals[c]).replace(/"/g,'""')+'"';
            })).join(',');
            csv += line + '\n';
          });
          if(window.ProgUI) ProgUI.step('Mengunduh fileвҖҰ', 95);
          _ieDownloadBlob(csv, 'maintenance_export_'+new Date().toISOString().slice(0,10)+'.csv', 'text/csv');
          toast('Riwayat Maintenance В· '+mdata.length+' baris diekspor','ok');
          _ieAddLog('Export', label, mdata.length+' baris');
          if(window.ProgUI) ProgUI.success(mdata.length+' baris maintenance berhasil di-export');
        }).catch(function(e){
          toast('Error export: '+(e.message||''),'err'); if(window.ProgUI)ProgUI.error('Error: '+(e.message||''));
        });
      return;
    }

    var orderCol = (table==='material_items') ? 'kode' : 'created_at';
    sb.from(table).select('*').order(orderCol, {ascending: table==='material_items'})
      .then(function(r){
        if(r.error){ toast('Gagal export: '+(r.error.message||'coba lagi'),'err'); if(window.ProgUI)ProgUI.error('Gagal export: '+(r.error.message||'coba lagi')); return; }
        var data = r.data||[];
        if(!data.length){ toast('Tidak ada data untuk diekspor','err'); if(window.ProgUI)ProgUI.error('Tidak ada data untuk diekspor'); return; }
        if(window.ProgUI) ProgUI.step('Menyusun '+data.length+' baris menjadi CSVвҖҰ', 75);

        /* в”Җв”Җ Pelanggan: export dalam format re-importable (sesuai schema import) в”Җв”Җ */
        if(table === 'pelanggan'){
          /* Kolom yang diekspor: sesuai schema import + extra info */
          var pelCols = [
            'cid','nama','hp','nik','alamat','kecamatan','kelurahan','rw','rt',
            'paket','jenis_pelanggan','tgl_pasang','status','tipe_recurring',
            'area_kode','odp_kode','nomor_port',
            'sn_ont','mac_ont','ont_model',
            'teknisi_pasang','lat','lng','keterangan'
          ];
          /* Build lookup: area_idвҶ’kode, odp_idвҶ’kode */
          var areaById = {}; (results[0]||[]).forEach(function(a){ areaById[a.id]=a.kode||a.nama||''; });
          var odpById  = {}; (results[3]||[]).forEach(function(o){ odpById[o.id]=o.kode||o.nama||''; });

          var headerRow = ['"No"'].concat(pelCols.map(function(c){ return '"'+c+'"'; })).join(',');
          var csv = headerRow + '\n';
          data.forEach(function(row, idx){
            var line = ['"'+(idx+1)+'"'].concat(pelCols.map(function(c){
              var v;
              if(c === 'area_kode') v = areaById[row.area_id] || row.area_coverage || '';
              else if(c === 'odp_kode') v = odpById[row.odp_id] || '';
              else v = row[c];
              if(v===null||v===undefined) v = '';
              v = String(v).replace(/"/g,'""');
              return '"'+v+'"';
            })).join(',');
            csv += line + '\n';
          });
          if(window.ProgUI) ProgUI.step('Mengunduh fileвҖҰ', 95);
          _ieDownloadBlob(csv, 'pelanggan_export_'+new Date().toISOString().slice(0,10)+'.csv', 'text/csv');
          toast('Pelanggan В· '+data.length+' baris diekspor (format re-importable)','ok');
          _ieAddLog('Export', label, data.length+' baris');
          if(window.ProgUI) ProgUI.success(data.length+' baris pelanggan berhasil di-export');
          return;
        }

        /* в”Җв”Җ Modul lain: export standar (semua kolom) в”Җв”Җ */
        var allCols = Object.keys(data[0]);
        var cols = allCols.filter(function(c){ return c !== 'id'; });

        var headerRow = ['"No"'].concat(cols.map(function(c){
          return '"'+(_fkHeader[c]||c)+'"';
        })).join(',');

        var csv = headerRow + '\n';
        data.forEach(function(row, idx){
          var line = ['"'+(idx+1)+'"'].concat(cols.map(function(c){
            var v = row[c];
            if(v===null||v===undefined) return '""';
            if(_fkHeader[c] && _isUUID(String(v))){ v = _resolve(c, v); }
            v = String(v).replace(/"/g,'""');
            return '"'+v+'"';
          })).join(',');
          csv += line + '\n';
        });

        if(window.ProgUI) ProgUI.step('Mengunduh fileвҖҰ', 95);
        _ieDownloadBlob(csv, table+'_export_'+new Date().toISOString().slice(0,10)+'.csv', 'text/csv');
        toast(label+' В· '+data.length+' baris diekspor','ok');
        _ieAddLog('Export', label, data.length+' baris');
        if(window.ProgUI) ProgUI.success(data.length+' baris '+label+' berhasil di-export');
      })
      .catch(function(e){ toast('Error: '+(e.message||'coba lagi'),'err'); if(window.ProgUI)ProgUI.error('Error: '+(e.message||'coba lagi')); });

  }).catch(function(e){ toast('Gagal muat referensi: '+(e.message||'coba lagi'),'err'); if(window.ProgUI)ProgUI.error('Gagal muat referensi: '+(e.message||'coba lagi')); });
}

/* в”Җв”Җ Download blob helper в”Җв”Җ */
function _ieDownloadBlob(content, filename, type){
  var blob = new Blob(['\uFEFF'+content], {type:type+';charset=utf-8;'});
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click();
  document.body.removeChild(a);
  setTimeout(function(){ URL.revokeObjectURL(url); }, 1000);
}

/* в”Җв”Җ Log helper в”Җв”Җ */
function _ieAddLog(action, label, detail){
  _ieLog.unshift({action:action, label:label, detail:detail, time:new Date()});
  var el = document.getElementById('ie-log-list');
  if(!el) return;
  if(!_ieLog.length){ el.innerHTML='<div style="text-align:center;padding:30px 0;color:var(--text3);font-size:12px"><i class="ti ti-inbox" style="font-size:28px;display:block;margin-bottom:8px;opacity:.4"></i>Belum ada riwayat</div>'; return; }
  el.innerHTML = _ieLog.map(function(l){
    var color = l.action==='Import' ? 'var(--c1)' : 'var(--green)';
    var ico   = l.action==='Import' ? 'ti-file-import' : 'ti-file-export';
    var t = l.time;
    var ts = (t.getDate()<10?'0':'')+t.getDate()+'/'+(t.getMonth()<9?'0':'')+(t.getMonth()+1)+'/'+t.getFullYear()+' '+(t.getHours()<10?'0':'')+t.getHours()+':'+(t.getMinutes()<10?'0':'')+t.getMinutes();
    return '<div style="display:flex;align-items:center;gap:10px;padding:9px 0;border-bottom:1px solid var(--border)">'+
      '<div style="width:32px;height:32px;border-radius:9px;background:rgba(0,0,0,.05);display:flex;align-items:center;justify-content:center;flex-shrink:0">'+
        '<i class="ti '+ico+'" style="font-size:15px;color:'+color+'"></i></div>'+
      '<div style="flex:1;min-width:0">'+
        '<div style="font-size:12px;font-weight:700;color:var(--text)">'+l.action+' В· '+_esc(l.label)+'</div>'+
        '<div style="font-size:10px;color:var(--text3)">'+_esc(l.detail)+' В· '+ts+'</div>'+
      '</div></div>';
  }).join('');
}

